<?php
namespace Tests\Feature;
use App\Domain\Characters\Actions\CreateCharacterAction;use App\Domain\Equipment\CharacterEquipmentService;use App\Domain\Equipment\EquipmentEligibilityService;use App\Domain\Inventory\CharacterInventorySummaryService;use App\Models\Character;use App\Models\CharacterClass;use App\Models\CharacterEquipment;use App\Models\Item;use App\Models\ItemInstance;use App\Models\ItemInstanceEvent;use App\Models\User;use Illuminate\Foundation\Testing\RefreshDatabase;use Illuminate\Support\Facades\DB;use Tests\TestCase;
class EquipmentRequirementsTest extends TestCase{use RefreshDatabase;private function item($overrides=[]){return Item::create(array_merge(['code'=>'req_'.uniqid(),'name'=>'Requirement item','item_type'=>'equipment','equipment_type'=>'weapon','required_level'=>1,'rarity'=>'common','is_stackable'=>false,'max_stack'=>1,'attack_bonus'=>5,'status'=>'active'],$overrides));}private function createItemInstance($character,$item){return ItemInstance::factory()->create(['character_id'=>$character->id,'item_id'=>$item->id,'status'=>'available']);}
public function test_new_character_gets_adventurer_and_client_cannot_choose_class(){$other=CharacterClass::factory()->create(['code'=>'mage']);$user=User::factory()->create();$character=app(CreateCharacterAction::class)->execute($user,'Requirement Hero');$this->assertSame('adventurer',$character->characterClass->code);$this->actingAs(User::factory()->create())->post(route('characters.store'),['name'=>'Client Class Hero','character_class_id'=>$other->id]);$created=Character::where('name','Client Class Hero')->firstOrFail();$this->assertSame('adventurer',$created->characterClass->code);}
public function test_level_class_and_missing_class_semantics_are_authoritative(){$warrior=CharacterClass::factory()->create(['code'=>'warrior']);$mage=CharacterClass::factory()->create(['code'=>'mage']);$character=Character::factory()->create(['level'=>4,'character_class_id'=>$warrior->id]);$item=$this->item(['required_level'=>5]);$item->allowedCharacterClasses()->sync([$warrior->id,$mage->id]);$instance=$this->createItemInstance($character,$item);$result=app(EquipmentEligibilityService::class)->evaluate($character,$instance,$item,'weapon_main',$item->allowedCharacterClasses,$warrior);$this->assertFalse($result->eligible());$this->assertContains('level_requirement_not_met',$result->reasonCodes());$character->level=5;$this->assertTrue(app(EquipmentEligibilityService::class)->evaluate($character,$instance,$item,'weapon_main',$item->allowedCharacterClasses,$warrior)->eligible());$character->character_class_id=null;$character->setRelation('characterClass',null);$this->assertContains('class_requirement_not_met',app(EquipmentEligibilityService::class)->evaluate($character,$instance,$item,'weapon_main',$item->allowedCharacterClasses,null)->reasonCodes());$item->allowedCharacterClasses()->sync([]);$item->setRelation('allowedCharacterClasses',collect());$this->assertTrue(app(EquipmentEligibilityService::class)->evaluate($character,$instance,$item,'weapon_main',collect(),null)->eligible());}
public function test_failed_replacements_keep_old_equipment_status_health_and_events(){$warrior=CharacterClass::factory()->create(['code'=>'warrior']);$mage=CharacterClass::factory()->create(['code'=>'mage']);$character=Character::factory()->create(['level'=>4,'character_class_id'=>$warrior->id,'current_health'=>77]);$oldItem=$this->item();$old=$this->createItemInstance($character,$oldItem);app(CharacterEquipmentService::class)->equip($character,$old->uuid,'weapon_main');foreach([['required_level'=>5,'classes'=>[]],['required_level'=>1,'classes'=>[$mage->id]]] as $config){$newItem=$this->item(['required_level'=>$config['required_level']]);$newItem->allowedCharacterClasses()->sync($config['classes']);$new=$this->createItemInstance($character,$newItem);$before=ItemInstanceEvent::count();try{app(CharacterEquipmentService::class)->equip($character,$new->uuid,'weapon_main');$this->fail('Expected eligibility rejection.');}catch(\InvalidArgumentException $e){}$this->assertSame($old->id,CharacterEquipment::where('character_id',$character->id)->value('item_instance_id'));$this->assertSame('equipped',$old->fresh()->status);$this->assertSame('available',$new->fresh()->status);$this->assertSame($before,ItemInstanceEvent::count());$this->assertSame(77,$character->fresh()->current_health);}}
public function test_persisted_incompatible_equipment_keeps_stats_and_is_marked(){$character=Character::factory()->create(['level'=>5]);$item=$this->item(['attack_bonus'=>10]);$instance=$this->createItemInstance($character,$item);app(CharacterEquipmentService::class)->equip($character,$instance->uuid,'weapon_main');$before=app(\App\Domain\Characters\CharacterStatsCalculator::class)->breakdown($character);$item->update(['required_level'=>10]);$after=app(\App\Domain\Characters\CharacterStatsCalculator::class)->breakdown($character);$this->assertSame($before->effective()->attack(),$after->effective()->attack());$source=$after->equipmentSources()[0];$this->assertFalse($source['eligibility_current']);$this->assertContains('level_requirement_not_met',$source['eligibility_reason_codes']);}
public function test_inventory_prepares_slot_eligibility_without_per_item_queries(){$character=Character::factory()->create();foreach(range(1,4) as $i)$this->createItemInstance($character,$this->item(['code'=>'batch_req_'.$i]));DB::flushQueryLog();DB::enableQueryLog();$summary=app(CharacterInventorySummaryService::class)->snapshot($character);$queries=collect(DB::getQueryLog())->filter(function($query){return stripos($query['query'],'character_class_item')!==false;})->count();$this->assertCount(4,$summary['item_instances']);$this->assertSame(1,$queries);$this->assertArrayHasKey('eligibility_by_slot',$summary['item_instances'][0]);}}
